def lcs_length(a, b):
    # dynamic programming for LCS length
    n, m = len(a), len(b)
    # memory optimization: only store 2 rows
    prev = [0]*(m+1)
    for i in range(1, n+1):
        cur = [0]*(m+1)
        ai = a[i-1]
        for j in range(1, m+1):
            if ai == b[j-1]:
                cur[j] = prev[j-1] + 1
            else:
                cur[j] = prev[j] if prev[j] >= cur[j-1] else cur[j-1]
        prev = cur
    return prev[m]

def lcs_ratio(a, b):
    if not a and not b: 
        return 1.0
    lcs = lcs_length(a, b)
    return 2*lcs/(len(a)+len(b))

